1	import { makeAgentContext, type AgentContext, type HookBus } from '@ax/core';
2	import { z } from 'zod';
3	import {
4	  parseRequestBody,
5	  requireAdmin,
6	  requireUser,
7	  writeServiceError,
8	  type RouteRequest,
9	  type RouteResponse,
10	} from './shared.js';
11	
12	// ---------------------------------------------------------------------------
13	// /admin/credentials* CRUD handlers (admin-only).
14	//
15	// Routes:
16	//   GET    /admin/credentials                                  → list (metadata only)
17	//   POST   /admin/credentials                                  → create
18	//   DELETE /admin/credentials/:scope/:ownerId/:ref             → delete
19	//
20	// All endpoints require an authenticated admin session (auth:require-user
21	// + isAdmin). Body cap: 64 KiB (ADMIN_BODY_MAX_BYTES). Body schema is
22	// re-validated at the route layer for friendly 400 messages — the
23	// credentials facade re-validates again, so this layer's looseness can't
24	// trick the store into accepting a malformed shape (but a route-layer
25	// reject avoids the round-trip).
26	//
27	// `/admin/credentials/kinds` (the kinds catalog) is mounted under the
28	// admin namespace for routing convenience but the auth gate is relaxed
29	// to `auth:require-user` — the catalog isn't admin-sensitive (it just
30	// answers "what flows does this deployment support?") and the settings
31	// UI for any authed user consumes it too. Same posture as a public
32	// "supported features" endpoint.
33	// ---------------------------------------------------------------------------
34	
35	const PLUGIN_NAME = '@ax/credentials-admin-routes';
36	
37	const REF_RE = /^[a-z0-9][a-z0-9_.-]{0,127}$/;
38	const KIND_RE = /^[a-z0-9][a-z0-9_-]{0,63}$/;
39	const OWNER_ID_RE = /^[A-Za-z0-9][A-Za-z0-9_.@-]{0,127}$/;
40	
41	/**
42	 * Body schema for `POST /admin/credentials`. Mirrors the credentials
43	 * facade's CredentialsSetInput (packages/credentials/src/plugin.ts) — the
44	 * facade re-validates so this layer can't be the only gate, but matching
45	 * shape here gives the operator a crisper 400.
46	 *
47	 * `payload` is the secret material as base64 — the bytes never traverse
48	 * JSON in the clear. The handler decodes to Uint8Array before the
49	 * `credentials:set` call.
50	 *
51	 * `.strict()` means unknown keys are a 400. We don't want to silently
52	 * accept e.g. `userId` typos that would otherwise be ignored.
53	 */
54	const createBodySchema = z
55	  .object({
56	    scope: z.enum(['global', 'user', 'agent']),
57	    ownerId: z.string().regex(OWNER_ID_RE).nullable(),
58	    ref: z.string().regex(REF_RE),
59	    kind: z.string().regex(KIND_RE),
60	    payload: z.string().min(1), // base64
61	    expiresAt: z.number().int().positive().optional(),
62	    metadata: z.record(z.string(), z.unknown()).optional(),
63	  })
64	  .strict()
65	  .superRefine((v, ctx) => {
66	    if (v.scope === 'global' && v.ownerId !== null) {
67	      ctx.addIssue({
68	        code: z.ZodIssueCode.custom,
69	        message: "ownerId must be null when scope='global'",
70	        path: ['ownerId'],
71	      });
72	    }
73	    if ((v.scope === 'user' || v.scope === 'agent') && v.ownerId === null) {
74	      ctx.addIssue({
75	        code: z.ZodIssueCode.custom,
76	        message: `ownerId is required when scope='${v.scope}'`,
77	        path: ['ownerId'],
78	      });
79	    }
80	  });
81	
82	export interface AdminRouteDeps {
83	  bus: HookBus;
84	}
85	
86	export function createAdminCredentialsHandlers(deps: AdminRouteDeps): {
87	  list: (req: RouteRequest, res: RouteResponse) => Promise<void>;
88	  create: (req: RouteRequest, res: RouteResponse) => Promise<void>;
89	  destroy: (req: RouteRequest, res: RouteResponse) => Promise<void>;
90	  kinds: (req: RouteRequest, res: RouteResponse) => Promise<void>;
91	} {
92	  // Per-handler ctx is acceptable for MVP. A subscriber observing audit
93	  // events sees `userId: 'admin'` in the ctx — the actual acting-user id
94	  // is communicated via subscriber payloads (which Phase 6 will add for
95	  // credentials).
96	  const ctx = makeAgentContext({
97	    sessionId: 'credentials-admin',
98	    agentId: PLUGIN_NAME,
99	    userId: 'admin',
100	  });
101	
102	  return {
103	    /** GET /admin/credentials */
104	    async list(req: RouteRequest, res: RouteResponse): Promise<void> {
105	      const actor = await requireAdmin(deps.bus, ctx, req, res);
106	      if (actor === null) return;
107	      try {
108	        const out = await deps.bus.call<
109	          Record<string, never>,
110	          { credentials: unknown[] }
111	        >('credentials:list', ctx, {});
112	        res.status(200).json(out);
113	      } catch (err) {
114	        if (writeServiceError(res, err)) return;
115	        throw err;
116	      }
117	    },
118	
119	    /** POST /admin/credentials */
120	    async create(req: RouteRequest, res: RouteResponse): Promise<void> {
121	      const actor = await requireAdmin(deps.bus, ctx, req, res);
122	      if (actor === null) return;
123	      const parsedBody = parseRequestBody(req.body);
124	      if (!parsedBody.ok) {
125	        res.status(parsedBody.status).json({ error: parsedBody.message });
126	        return;
127	      }
128	      const result = createBodySchema.safeParse(parsedBody.value);
129	      if (!result.success) {
130	        const first = result.error.issues[0];
131	        res.status(400).json({
132	          error:
133	            first?.message !== undefined && first.message.length > 0
134	              ? first.message
135	              : 'invalid-payload',
136	        });
137	        return;
138	      }
139	      const data = result.data;
140	      let payload: Uint8Array;
141	      try {
142	        payload = new Uint8Array(Buffer.from(data.payload, 'base64'));
143	      } catch {
144	        res.status(400).json({ error: 'invalid-payload' });
145	        return;
146	      }
147	      // Empty bytes after base64 decode = the operator passed a string
148	      // that decoded to nothing. Either a typo or an attempted tombstone
149	      // bypass; either way reject.
150	      if (payload.length === 0) {
151	        res.status(400).json({ error: 'payload must decode to non-empty bytes' });
152	        return;
153	      }
154	      try {
155	        await deps.bus.call('credentials:set', ctx, {
156	          scope: data.scope,
157	          ownerId: data.ownerId,
158	          ref: data.ref,
159	          kind: data.kind,
160	          payload,
161	          ...(data.expiresAt !== undefined ? { expiresAt: data.expiresAt } : {}),
162	          ...(data.metadata !== undefined ? { metadata: data.metadata } : {}),
163	        });
164	        // Echo metadata-only — the secret bytes never traverse the response
165	        // wire. The createdAt is the server's clock (the facade stamps the
166	        // same value into the envelope; we don't have a way to read it back
167	        // without an extra round-trip, so we use Date.now() here — the two
168	        // stamps are within ms of each other).
169	        const credential: Record<string, unknown> = {
170	          scope: data.scope,
171	          ownerId: data.ownerId,
172	          ref: data.ref,
173	          kind: data.kind,
174	          createdAt: new Date().toISOString(),
175	        };
176	        if (data.expiresAt !== undefined) {
177	          credential.expiresAt = new Date(data.expiresAt).toISOString();
178	        }
179	        if (data.metadata !== undefined) credential.metadata = data.metadata;
180	        res.status(201).json({ credential });
181	      } catch (err) {
182	        if (writeServiceError(res, err)) return;
183	        throw err;
184	      }
185	    },
186	
187	    /**
188	     * GET /admin/credentials/kinds — catalog of supported credential
189	     * kinds and their flow shape (paste vs oauth). Auth gate is relaxed
190	     * to any authed user (settings UI consumes the same route).
191	     */
192	    async kinds(req: RouteRequest, res: RouteResponse): Promise<void> {
193	      const actor = await requireUser(deps.bus, ctx, req, res);
194	      if (actor === null) return;
195	      try {
196	        const out = await deps.bus.call<
197	          Record<string, never>,
198	          { kinds: Array<{ kind: string; flow: string }> }
199	        >('credentials:list-kinds', ctx, {});
200	        res.status(200).json(out);
201	      } catch (err) {
202	        if (writeServiceError(res, err)) return;
203	        throw err;
204	      }
205	    },
206	
207	    /** DELETE /admin/credentials/:scope/:ownerId/:ref */
208	    async destroy(req: RouteRequest, res: RouteResponse): Promise<void> {
209	      const actor = await requireAdmin(deps.bus, ctx, req, res);
210	      if (actor === null) return;
211	      const { scope, ownerId, ref } = req.params;
212	      if (
213	        scope === undefined ||
214	        scope.length === 0 ||
215	        ownerId === undefined ||
216	        ownerId.length === 0 ||
217	        ref === undefined ||
218	        ref.length === 0
219	      ) {
220	        res.status(400).json({ error: 'missing-params' });
221	        return;
222	      }
223	      // The URL placeholder for "no owner" (scope='global') is `_` — JSON
224	      // `null` doesn't path-encode. We translate before the bus call;
225	      // the facade will reject scope='global' with non-null ownerId
226	      // anyway, which is the contract the URL layer just decoded.
227	      const ownerIdResolved = ownerId === '_' ? null : ownerId;
228	      if (scope !== 'global' && scope !== 'user' && scope !== 'agent') {
229	        res.status(400).json({ error: 'invalid-scope' });
230	        return;
231	      }
232	      try {
233	        await deps.bus.call('credentials:delete', ctx, {
234	          scope,
235	          ownerId: ownerIdResolved,
236	          ref,
237	        });
238	        res.status(204).end();
239	      } catch (err) {
240	        if (writeServiceError(res, err)) return;
241	        throw err;
242	      }
243	    },
244	  };
245	}
246	
247	/**
248	 * Register all three admin routes against @ax/http-server. Returned
249	 * unregister callbacks should be tracked by the plugin and called on
250	 * shutdown so a re-init in tests doesn't trip duplicate-route.
251	 */
252	export async function registerAdminCredentialsRoutes(
253	  bus: HookBus,
254	  initCtx: AgentContext,
255	): Promise<Array<() => void>> {
256	  const handlers = createAdminCredentialsHandlers({ bus });
257	  const routes: Array<{
258	    method: 'GET' | 'POST' | 'DELETE';
259	    path: string;
260	    handler: (req: RouteRequest, res: RouteResponse) => Promise<void>;
261	  }> = [
262	    { method: 'GET', path: '/admin/credentials', handler: handlers.list },
263	    // `/admin/credentials/kinds` is a literal route — exact-match dispatch
264	    // in @ax/http-server's router wins over the `:scope/:ownerId/:ref`
265	    // pattern below regardless of registration order, but we list it first
266	    // for readability.
267	    { method: 'GET', path: '/admin/credentials/kinds', handler: handlers.kinds },
268	    { method: 'POST', path: '/admin/credentials', handler: handlers.create },
269	    {
270	      method: 'DELETE',
271	      path: '/admin/credentials/:scope/:ownerId/:ref',
272	      handler: handlers.destroy,
273	    },
274	  ];
275	  const unregisters: Array<() => void> = [];
276	  for (const route of routes) {
277	    const result = await bus.call<unknown, { unregister: () => void }>(
278	      'http:register-route',
279	      initCtx,
280	      route,
281	    );
282	    unregisters.push(result.unregister);
283	  }
284	  return unregisters;
285	}
286	
287	export { ADMIN_BODY_MAX_BYTES } from './shared.js';
