21	function mkRes(): {
22	  res: RouteResponse;
23	  statusOf: () => number;
24	  bodyOf: () => unknown;
25	} {
26	  let _status = 200;
27	  let _body: unknown = undefined;
28	  const res: RouteResponse = {
29	    status(n: number) {
30	      _status = n;
31	      return res;
32	    },
33	    json(v: unknown) {
34	      _body = v;
35	    },
