48	function mkReq(opts: {
49	  body?: unknown;
50	  params?: Record<string, string>;
51	}): RouteRequest {
52	  return {
53	    headers: {},
54	    body:
55	      opts.body === undefined
56	        ? Buffer.alloc(0)
57	        : Buffer.from(JSON.stringify(opts.body)),
58	    cookies: {},
59	    query: {},
60	    params: opts.params ?? {},
61	    signedCookie: () => null,
62	  };
63	}
