1	// ---------------------------------------------------------------------------
2	// Runner env read + validate — claude-sdk variant.
3	//
4	// Reads the host-injected per-session proxy fields plus the runner
5	// endpoint, session id, auth token, and workspace root. The proxy fields
6	// are populated when @ax/credential-proxy is loaded.
7	// Exactly one of AX_PROXY_ENDPOINT (subprocess sandbox, TCP) or
8	// AX_PROXY_UNIX_SOCKET (k8s sandbox, Unix socket → bridge) is required —
9	// they drive different transports.
10	//
11	// AX_RUNNER_ENDPOINT is an opaque URI (I1). The IPC client parses the
12	// scheme; see @ax/ipc-protocol/ipc-client.ts.
13	//
14	// Empty-string values are treated as missing: an env var set to '' is
15	// almost always a wiring bug, not an intentional value. Failing loud here
16	// beats a confusing downstream error.
17	// ---------------------------------------------------------------------------
18	
19	export interface RunnerEnv {
20	  runnerEndpoint: string;
21	  sessionId: string;
22	  authToken: string;
23	  workspaceRoot: string;
24	  /**
25	   * Per-session credential-proxy TCP endpoint (subprocess sandbox).
26	   * Mutually exclusive with `proxyUnixSocket`. When present, the SDK calls
27	   * api.anthropic.com directly through HTTPS_PROXY (set by sandbox-
28	   * subprocess); the runner does NOT start a bridge.
29	   */
30	  proxyEndpoint?: string;
31	  /**
32	   * Per-session credential-proxy Unix socket path (k8s sandbox).
33	   * Mutually exclusive with `proxyEndpoint`. When present, the runner
34	   * starts a TCP-to-unix bridge via @ax/credential-proxy-bridge and
35	   * rewrites HTTP(S)_PROXY in-process to point at the local bridge
36	   * port. Off-the-shelf libraries inside the sandbox can't reach a
37	   * Unix socket directly; the bridge gives them a loopback TCP target.
38	   */
39	  proxyUnixSocket?: string;
40	}
41	
42	export class MissingEnvError extends Error {
43	  public override readonly name = 'MissingEnvError';
44	  constructor(public readonly varName: string) {
45	    super(`missing required env: ${varName}`);
46	  }
47	}
48	
49	export function readRunnerEnv(env: NodeJS.ProcessEnv = process.env): RunnerEnv {
50	  const need = (k: string): string => {
51	    const v = env[k];
52	    if (typeof v !== 'string' || v.length === 0) throw new MissingEnvError(k);
53	    return v;
54	  };
55	  const opt = (k: string): string | undefined => {
56	    const v = env[k];
57	    return typeof v === 'string' && v.length > 0 ? v : undefined;
58	  };
59	
60	  const proxyEndpoint = opt('AX_PROXY_ENDPOINT');
61	  const proxyUnixSocket = opt('AX_PROXY_UNIX_SOCKET');
62	
63	  // The two AX_PROXY_* transport vars are mutually exclusive (subprocess
64	  // sandbox sets one, k8s sandbox sets the other). Accepting both would
65	  // silently pick the bridge path in setupProxy() and route traffic
66	  // through the wrong transport — fail loud at boot instead.
67	  if (proxyEndpoint !== undefined && proxyUnixSocket !== undefined) {
68	    throw new MissingEnvError(
69	      'AX_PROXY_ENDPOINT xor AX_PROXY_UNIX_SOCKET (mutually exclusive — one set per session)',
70	    );
71	  }
72	
73	  // I9 — exactly one proxy path must be configured. The host's
74	  // credential-proxy sets one of the two; if both are missing, the
75	  // runner has no way to reach an LLM and we fail loud at boot rather
76	  // than at first SDK call.
77	  if (proxyEndpoint === undefined && proxyUnixSocket === undefined) {
78	    throw new MissingEnvError(
79	      'AX_PROXY_ENDPOINT or AX_PROXY_UNIX_SOCKET',
80	    );
81	  }
