                        <Badge key={c.slot} variant="outline" className="text-xs mr-1 font-mono">{c.slot}</Badge>
                      ))
                    )}
                  </TableCell>
                  <TableCell className="text-xs text-muted-foreground">
                    {new Date(s.updatedAt).toLocaleString()}
