              </p>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setPendingDelete(null)}>Cancel</Button>
                <Button variant="destructive" onClick={() => void handleDelete(pendingDelete)}>Delete</Button>
              </div>
            </DialogContent>
          </Dialog>
