          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Install a new skill</DialogTitle>
            </DialogHeader>
            <SkillEditor onSaved={() => { setShowNew(false); void refresh(); }} onCancel={() => setShowNew(false)} />
