              <SkillEditor
                skillId={editingId}
                onSaved={() => { setEditingId(null); void refresh(); }}
                onCancel={() => setEditingId(null)}
              />
            </DialogContent>
          </Dialog>
        )}

        {pendingDelete !== null && (
          <Dialog open={true} onOpenChange={(o) => { if (!o) setPendingDelete(null); }}>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Delete skill?</DialogTitle>
              </DialogHeader>
              <p className="text-sm text-muted-foreground">
                Delete <code className="font-mono">{pendingDelete}</code>? This cannot be undone.
                If the skill is attached to any agent, the delete will fail and you'll need to detach first.
              </p>
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setPendingDelete(null)}>Cancel</Button>
                <Button variant="destructive" onClick={() => void handleDelete(pendingDelete)}>Delete</Button>
              </div>
            </DialogContent>
          </Dialog>
        )}
      </CardContent>
    </Card>
  );
}
