146	        .execute();
147	    },
148	
149	    async resolve(skillIds) {
150	      if (skillIds.length === 0) return [];
151	
152	      const rows = await db
153	        .selectFrom('skills_v1_skills')
154	        .selectAll()
155	        .where('skill_id', 'in', skillIds)
156	        .execute();
157	
158	      const byId = new Map(rows.map((r) => [r.skill_id, r]));
159	
160	      // Preserve input order; drop unknown ids silently.
161	      const result: ResolvedSkill[] = [];
162	      for (const id of skillIds) {
163	        const row = byId.get(id);
164	        if (row === undefined) continue;
165	        result.push({
166	          id: row.skill_id,
167	          capabilities: parseCapabilities(row.manifest_yaml, row.skill_id),
168	          bodyMd: row.body_md,
169	          manifestYaml: row.manifest_yaml,
170	        });
171	      }
172	      return result;
173	    },
174	  };
175	}

